	c[++b]=d;
	son=b;
	while(son>1)
	{
		pa=son>>1;
		if(c[son]>=c[pa])
		{
			break;
		}
		swap(c[son],c[pa]);
		son=pa;
	}
}
int get()
{
	int pa,son,res;
	res=c[1];
	c[1]=c[b--];
	pa=1;
	while(pa*2<=b)
	{
		son=pa*2;
		if(son<b&&c[son+1]<c[son])
		{
			son++;
		}
		if(c[pa]<=c[son])
		{
			break;
		}
